import { html, customElement } from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type { PreValueSourceTypeWithSettings } from "@umbraco-forms/generated";
import { FormsPrevalueSourceTypeCollectionRepository } from "../../../../provider-types/prevaluesource-types/repository/collection/index.js";
import type { FormsPrevalueSourceCreateOptionsModalData } from "./index.js";

const elementName = "forms-prevaluesource-create-options-modal";

@customElement(elementName)
export class FormsPrevalueSourceCreateOptionsModalElement extends UmbModalBaseElement<FormsPrevalueSourceCreateOptionsModalData> {
  #prevalueSourceTypes: Array<PreValueSourceTypeWithSettings> = [];

  constructor() {
    super();

    this.#initialize();
  }

  async #initialize() {
    const repository = new FormsPrevalueSourceTypeCollectionRepository(this);
    const { data } = await repository.requestCollection();
    this.#prevalueSourceTypes = data?.items || [];
    this.requestUpdate();
  }

  #onClick(id: string) {
    const href = `section/forms/workspace/prevaluesource/create/${id}`;
    window.history.pushState({}, "", href);
    this._submitModal();
  }

  render() {
    return html`<umb-body-layout headline=${this.localize.term('formPrevalueSources_choosePrevalueSourceType')}>
      <uui-box>
        <uui-ref-list>
          ${this.#prevalueSourceTypes.map(
            (prevalueSourceType) =>
              html`<umb-ref-item
                selectable
                .name=${prevalueSourceType.name}
                .detail=${prevalueSourceType.description}
                .icon=${prevalueSourceType.icon}
                @click=${() => this.#onClick(prevalueSourceType.id)}
              >
              </umb-ref-item>`
          )}
        </uui-ref-list>
      </uui-box>
      <uui-button
        slot="actions"
        label=${this.localize.term("general_cancel")}
        @click=${this._rejectModal}
      ></uui-button>
    </umb-body-layout>`;
  }
}

export default FormsPrevalueSourceCreateOptionsModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsPrevalueSourceCreateOptionsModalElement;
  }
}
